const express = require('express');
const multer = require('multer');
const fs = require('fs');
const libxmljs = require('libxmljs');

const app = express();
const upload = multer({ dest: 'uploads/' });

app.post('/upload', upload.single('xmlFile'), (req, res) => {
    const xmlFilePath = req.file.path;

    libxmljs.parseXmlFile(xmlFilePath, {noentSubs: true}, (err, doc) => {
        if (err) {
            return res.status(500).send('Error parsing XML file');
        }

        try {
            const configObject = extractConfig(doc);
            res.json(configObject);
        } catch (parseErr) {
            fs.unlinkSync(xmlFilePath); // Clean up the uploaded file
            return res.status(400).send('Error extracting configuration from XML');
        }

        fs.unlinkSync(xmlFilePath); // Clean up the uploaded file
    });
});

function extractConfig(doc) {
    const rootNode = doc.get('//config'); // Assuming the root element is named 'config'
    if (!rootNode) {
        throw new Error('No config node found in XML');
    }

    const configObject = {};

    rootNode.childNodes().forEach(child => {
        if (child.type() === 'element') {
            configObject[child.name()] = child.text();
        }
    });

    return configObject;
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
});